class Solution:
    def isIsomorphic(self, s, t):
        def to_pattern(x):
            mapping = {}
            result = []
            idx = 0
            for c in x:
                if c not in mapping:
                    mapping[c] = idx
                    idx += 1
                result.append(mapping[c])
            return result
        return to_pattern(s) == to_pattern(t)

