var isIsomorphic = function(s, t) {
    const sToT = new Map();
    const tToS = new Map();
    for (let i = 0; i < s.length; i++) {
        const cs = s[i], ct = t[i];
        if (sToT.has(cs)) {
            if (sToT.get(cs) !== ct) return false;
        } else {
            if (tToS.has(ct)) return false;
            sToT.set(cs, ct);
            tToS.set(ct, cs);
        }
    }
    return true;
};
